import React, { useEffect, useState } from "react";
import "./styles.css";

import Modal from "./components/Modal";
import AssetForm from "./components/AssetForm";
import IncidentForm from "./components/IncidentForm";
import TenantForm from "./components/TenantForm";

const ASSET_API = "http://localhost:5001";
const INCIDENT_API = "http://localhost:5002";
const TENANT_API = "http://localhost:5003";

function App() {
  const [tenantId, setTenantId] = useState("");
  const [tenants, setTenants] = useState([]);
  const [assets, setAssets] = useState([]);
  const [incidents, setIncidents] = useState([]);

  const [showAsset, setShowAsset] = useState(false);
  const [showIncident, setShowIncident] = useState(false);
  const [showTenant, setShowTenant] = useState(false);

  /* ================= FETCH DATA ================= */

  const fetchTenants = async () => {
    const res = await fetch(`${TENANT_API}/tenants`);
    const data = await res.json();
    setTenants(data);
    if (data.length > 0 && !tenantId) {
      setTenantId(data[0].id);
    }
  };

  const fetchAssets = async () => {
    if (!tenantId) return;
    const res = await fetch(`${ASSET_API}/assets?tenantId=${tenantId}`);
    const data = await res.json();
    setAssets(data);
  };

  const fetchIncidents = async () => {
    if (!tenantId) return;
    const res = await fetch(`${INCIDENT_API}/incidents?tenantId=${tenantId}`);
    const data = await res.json();
    setIncidents(data);
  };

  useEffect(() => {
    fetchTenants();
  }, []);

  useEffect(() => {
    fetchAssets();
    fetchIncidents();
  }, [tenantId]);

  /* ================= UI ================= */

  return (
    <div className="container">

      {/* HEADER */}
      <div className="header">
        <div className="title">Multi-Tenant ITOM</div>

        <select value={tenantId} onChange={(e) => setTenantId(e.target.value)}>
          {tenants.map(t => (
            <option key={t.id} value={t.id}>{t.name}</option>
          ))}
        </select>
      </div>

      {/* BUTTONS */}
      <div className="button-group">
        <button onClick={() => setShowTenant(true)}>+ Tenant</button>
        <button onClick={() => setShowAsset(true)}>+ Asset</button>
        <button onClick={() => setShowIncident(true)}>+ Incident</button>
      </div>

      {/* ASSETS */}
      <div className="section">
        <div className="section-title">Assets</div>

        <div className="card-grid">
          {assets.map(a => (
            <div className="card" key={a.id}>
              <div className="card-title">{a.name}</div>
              <div className="card-sub">{a.type}</div>
            </div>
          ))}
        </div>
      </div>

      {/* INCIDENTS */}
      <div className="section">
        <div className="section-title">Incidents</div>

        {incidents.map(i => (
          <div
            key={i.id}
            className={`incident-card ${i.severity?.toLowerCase()}`}
          >
            <div>{i.description}</div>
            <div className="card-sub">{i.severity}</div>
          </div>
        ))}
      </div>

      {/* MODALS */}
      {showAsset && (
        <Modal onClose={() => setShowAsset(false)}>
          <AssetForm tenantId={tenantId} onSuccess={() => {
            fetchAssets();
            setShowAsset(false);
          }} />
        </Modal>
      )}

      {showIncident && (
        <Modal onClose={() => setShowIncident(false)}>
          <IncidentForm tenantId={tenantId} assets={assets} onSuccess={() => {
            fetchIncidents();
            setShowIncident(false);
          }} />
        </Modal>
      )}

      {showTenant && (
        <Modal onClose={() => setShowTenant(false)}>
          <TenantForm onSuccess={() => {
            fetchTenants();
            setShowTenant(false);
          }} />
        </Modal>
      )}

    </div>
  );
}

export default App;
